const text = $json.text ?? $json.data ?? '';
const fileName = '2026-04-14-openbrain-multi-chunk-test.txt';
const titleBase = fileName.replace(/\.[^.]+$/, '');
const maxChars = 1200;

function chunkText(input, size) {
  const normalized = String(input).trim();
  if (!normalized) return [];
  const chunks = [];
  let index = 0;
  while (index < normalized.length) {
    chunks.push(normalized.slice(index, index + size).trim());
    index += size;
  }
  return chunks.filter(Boolean);
}

const chunks = chunkText(text, maxChars);
const total = chunks.length || 1;
const ingestedAt = new Date().toISOString();

return chunks.map((chunk, i) => ({
  json: {
    source: 'file_ingest',
    category: 'project_note',
    title: `${titleBase} :: chunk ${String(i + 1).padStart(2, '0')}`,
    content: chunk,
    tags: [],
    metadata_json: {
      filename: fileName,
      chunk_index: i + 1,
      total_chunks: total,
      ingested_at: ingestedAt
    }
  }
}));
